// Attach workflow metadata every collector inherits
const items = $input.all();
const ctx = {
  workflow_name: '{{ COLLECTOR_NAME }}',
  source_slug:   '{{ SOURCE_SLUG }}',
  run_id:        `run_${Date.now()}`,
  started_at:    new Date().toISOString(),
  max_items:     100,
};
return [{ json: { ...items[0]?.json, _ctx: ctx } }];
